export const IconSizes = [12, 16, 20, 24, 32] as const;
export type IconSize = (typeof IconSizes)[number];

export const IconInnerSizes = [10, 12, 16, 20, 24] as const;
export type IconInnerSize = (typeof IconInnerSizes)[number];

export const DEFAULT_ICON_SIZE: IconSize = 16;

/**
 * Mapping from Icon container size to Base Icon (SVG) size
 * Based on the design system specifications
 */
export const IconInnerSizeMap: Record<IconSize, IconInnerSize> = {
  12: 10,
  16: 12,
  20: 16,
  24: 20,
  32: 24,
} as const;
